const aiResp = $input.first().json;
let analysis;
try {
  const c = aiResp.choices[0].message.content;
  analysis = JSON.parse(c.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch(e) {
  analysis = { market_summary: 'AI analysis failed', recommendations: [], aging_alerts: [] };
}

return [{ json: { ...analysis, analyzed_at: new Date().toISOString() } }];
